parameters.jsCode:
function clean(value) {
  return String(value || '')
    .replace(/\u00a0/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function clampScore(value, fallback) {
  const score = Number(value);
  if (!Number.isFinite(score)) return fallback;
  return Math.max(0, Math.min(100, Math.round(score)));
}

function priorityFor(score, recommendation) {
  if (recommendation === 'skip') return 'low';
  if (recommendation === 'apply' && score >= 80) return 'high';
  if (score >= 65) return 'medium';
  return 'low';
}

function parseJsonText(value) {
  const text = clean(value);
  if (!text) return null;

  try {
    return JSON.parse(text);
  } catch {}

  const fenced = text.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (fenced) {
    try {
      return JSON.parse(fenced[1]);
    } catch {}
  }

  const start = text.indexOf('{');
  const end = text.lastIndexOf('}');
  if (start !== -1 && end > start) {
    try {
      return JSON.parse(text.slice(start, end + 1));
    } catch {}
  }

  return null;
}

function generationText(value) {
  const generations = value?.generations;
  if (!Array.isArray(generations)) return '';

  for (const group of generations) {
    const entries = Array.isArray(group) ? group : [group];
    for (const entry of entries) {
      const text = entry?.text ?? entry?.message?.content ?? entry?.content;
      if (typeof text === 'string' && text.trim()) return text;
    }
  }

  return '';
}

function hasReviewShape(value) {
  return (
    value &&
    typeof value === 'object' &&
    Object.prototype.hasOwnProperty.call(value, 'fit_score') &&
    Object.prototype.hasOwnProperty.call(value, 'recommendation') &&
    Object.prototype.hasOwnProperty.call(value, 'reason')
  );
}

function coerceReview(value) {
  if (!value) return null;
  if (typeof value === 'string') return parseJsonText(value);
  if (hasReviewShape(value)) return value;
  if (typeof value !== 'object') return null;

  const generatedText = generationText(value) || generationText(value.response);
  if (generatedText) return parseJsonText(generatedText);

  for (const key of ['output', 'text', 'response', 'content', 'message']) {
    const nested = value[key];
    if (!nested || nested === value) continue;
    const parsed = coerceReview(nested);
    if (parsed) return parsed;
  }

  return null;
}

function extractReview(json) {
  if (json.error) {
    return { valid: false, error: clean(json.error).slice(0, 220) || 'AI node returned an error.' };
  }

  const output = coerceReview(json);
  if (!hasReviewShape(output)) {
    return { valid: false, error: 'AI output was empty or not JSON.' };
  }

  return { valid: true, data: output };
}

function normalizeChoice(value, allowed, fallback) {
  const normalized = clean(value).toLowerCase().replace(/[^a-z_ -]/g, '').replace(/\s+/g, '_');
  return allowed.includes(normalized) ? normalized : fallback;
}

function normalizeResumeVariant(value, fallback = 'general') {
  const normalized = clean(value)
    .toLowerCase()
    .replace(/[^a-z0-9_ -]/g, '')
    .replace(/\s+/g, '_')
    .replace(/^_+|_+$/g, '')
    .slice(0, 40);

  return normalized || fallback;
}

function list(value) {
  if (Array.isArray(value)) return value.map(clean).filter(Boolean).slice(0, 3);
  const text = clean(value);
  return text ? [text] : [];
}

function appendNote(existing, note) {
  const base = clean(existing);
  const extra = clean(note);
  if (!extra) return base;
  const combined = base ? `${base} | ${extra}` : extra;
  return combined.slice(0, 1400);
}

function decisiveRecommendation(rawRecommendation, score, json, confidence) {
  const recommendation = normalizeChoice(rawRecommendation, ['apply', 'consider', 'skip'], 'skip');
  const status = clean(json.status).toLowerCase();
  const source = clean(json.source).toLowerCase();
  const descriptionSource = clean(json.description_source).toLowerCase();

  if (status === 'closed' || score <= 39) return 'skip';
  if (score < 65) return 'skip';
  if (confidence === 'low' && score < 75) return 'skip';
  if ((source === 'ziprecruiter' || descriptionSource === 'email') && score < 75) return 'skip';
  if (recommendation === 'skip') return 'skip';
  if (score >= 80 && recommendation === 'apply') return 'apply';
  if (score >= 80 && confidence === 'high') return 'apply';
  return 'consider';
}

function calibratedScore(score, json, confidence) {
  let calibrated = score;
  const source = clean(json.source).toLowerCase();
  const descriptionSource = clean(json.description_source).toLowerCase();

  if ((source === 'ziprecruiter' || descriptionSource === 'email') && calibrated > 75) calibrated = 75;
  if (confidence === 'low' && calibrated > 72) calibrated = 72;
  if (json.status === 'closed') calibrated = Math.min(calibrated, 20);

  return calibrated;
}

return items
  .map(item => {
    const json = item.json || {};
    const baselineScore = clampScore(json.fit_score, 0);
    const review = extractReview(json);

    if (!review.valid) {
      return {
        json: {
          ...json,
          fit_score: baselineScore,
          priority: json.priority || priorityFor(baselineScore, 'consider'),
          notes: appendNote(json.notes, `AI review unavailable; kept deterministic score. ${review.error}`),
        },
      };
    }

    const data = review.data;
    const rawScore = clampScore(data.fit_score, baselineScore);
    const confidence = normalizeChoice(data.confidence, ['high', 'medium', 'low'], json.ai_confidence || 'medium');
    const aiScore = calibratedScore(rawScore, json, confidence);
    const recommendation = decisiveRecommendation(data.recommendation, aiScore, json, confidence);
    const finalPriority = priorityFor(aiScore, recommendation);
    const resumeVariant = normalizeResumeVariant(data.resume_variant, json.resume_variant || 'general');
    const reason = clean(data.reason).slice(0, 280) || 'No concise reason returned.';
    const strengths = list(data.strengths);
    const risks = list(data.risks);
    const details = [
      `AI ${recommendation}/${finalPriority}/${aiScore}: ${reason}`,
      strengths.length ? `Strengths: ${strengths.join('; ')}` : '',
      risks.length ? `Risks: ${risks.join('; ')}` : '',
    ].filter(Boolean).join(' ');

    return {
      json: {
        ...json,
        fit_score: aiScore,
        priority: finalPriority,
        resume_variant: recommendation === 'skip' || resumeVariant === 'none' ? '' : resumeVariant,
        status: json.status === 'closed' ? 'closed' : json.status || 'new',
        notes: appendNote(json.notes, details),
        ai_recommendation: recommendation,
        ai_reason: reason,
        ai_score: aiScore,
        ai_confidence: confidence,
        ai_review_valid: true,
      },
    };
  })
  .sort((a, b) => Number(b.json.fit_score || 0) - Number(a.json.fit_score || 0));

const originals = [];
const browserByKey = new Map();

for (const item of items) {
  const json = item.json || {};
  const key = String(json.job_key || '').trim();

  if (json.browser_fetch_record_type === 'browser') {
    if (key) browserByKey.set(key, json);
    continue;
  }

  originals.push(json);
}

function browserFallbackFor(original) {
  const status = original.browser_fetch_url ? 'missing_fetch_result' : 'no_url';
  return {
    browser_fetch_status: status,
    browser_description: '',
    browser_description_source: '',
    browser_page_title: '',
    browser_final_url: '',
    browser_job_closed: false,
    browser_excerpt: '',
    browser_error: status === 'missing_fetch_result'
      ? 'No browser fetch result was returned for this job.'
      : 'Browser fetch skipped.',
    browser_fetched_at: new Date().toISOString(),
    ai_profile_config: '',
    ai_profile_path: '',
    ai_profile_status: '',
    ai_profile_error: '',
  };
}

return originals
  .sort((a, b) => Number(a.browser_fetch_index ?? 0) - Number(b.browser_fetch_index ?? 0))
  .map(original => {
    const browser = browserByKey.get(String(original.job_key || '').trim()) || browserFallbackFor(original);
    const {
      browser_fetch_record_type,
      browser_fetch_source,
      ...browserFields
    } = browser;

    return {
      json: {
        ...original,
        ...browserFields,
      },
    };
  });

const jobs = items
  .map(item => {
    const json = item.json || {};
    return {
      job_key: json.job_key || '',
      source: json.source || '',
      browser_fetch_index: json.browser_fetch_index ?? '',
      browser_fetch_url: json.browser_fetch_url || '',
    };
  })
  .filter(job => job.job_key);

return [{
  json: {
    batch_source: 'all',
    browser_fetch_batch_count: jobs.length,
    fetchable_job_count: jobs.filter(job => String(job.browser_fetch_url || '').trim()).length,
    jobs,
  },
}];

function browserRow(parsed = {}) {
  return {
    json: {
      browser_fetch_record_type: 'browser',
      job_key: parsed.job_key || '',
      browser_fetch_index: parsed.browser_fetch_index ?? '',
      browser_fetch_source: parsed.browser_fetch_source || parsed.source || '',
      browser_fetch_status: parsed.status || 'unknown',
      browser_description: parsed.description || '',
      browser_description_source: parsed.description_source || '',
      browser_page_title: parsed.page_title || '',
      browser_final_url: parsed.final_url || parsed.url || '',
      browser_job_closed: Boolean(parsed.job_closed || parsed.jobClosed),
      browser_excerpt: parsed.visible_text_excerpt || '',
      browser_error: parsed.error || parsed.message || '',
      browser_fetched_at: parsed.fetched_at || '',
      ai_profile_config: parsed.profile_config || '',
      ai_profile_path: parsed.profile_path || '',
      ai_profile_status: parsed.profile_status || '',
      ai_profile_error: parsed.profile_error || '',
    },
  };
}

function emptyBatchRow() {
  return browserRow({
    status: 'empty_batch',
    error: 'No browser fetch rows were returned for this batch.',
    fetched_at: new Date().toISOString(),
  });
}

function parseStdoutRow(item) {
  const stdout = String(item.json.stdout || '').trim();
  const stderr = String(item.json.stderr || '').trim();

  try {
    return browserRow(stdout ? JSON.parse(stdout) : {});
  } catch (error) {
    return browserRow({
      status: 'parse_error',
      error: `Could not parse browser helper stdout: ${error.message}`,
      raw_stdout: stdout.slice(0, 1000),
      stderr,
    });
  }
}

const output = [];

for (const item of items) {
  const json = item.json || {};

  if (Array.isArray(json.results)) {
    const batchProfile = {
      profile_config: json.profile_config || '',
      profile_path: json.profile_path || '',
      profile_status: json.profile_status || '',
      profile_error: json.profile_error || '',
    };

    for (const result of json.results) {
      output.push(browserRow({
        ...batchProfile,
        ...result,
      }));
    }
    continue;
  }

  if (json.status || json.description || json.description_source || json.error || json.message) {
    output.push(browserRow(json));
    continue;
  }

  output.push(parseStdoutRow(item));
}

return output.length ? output : [emptyBatchRow()];

const REPROCESS_STATUSES = new Set(['refresh', 'rescore', 'retry', 'rerun']);
const SOURCE_RANK = {
  linkedin: 6,
  jobright: 5,
  glassdoor: 4,
  handshake: 4,
  gmail: 2,
  ziprecruiter: 1,
};

function clean(value) {
  return String(value || '')
    .replace(/\u00a0/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function normalizeText(value) {
  return clean(value)
    .toLowerCase()
    .replace(/\b(incorporated|inc|llc|ltd|corp|corporation|company|co)\b\.?/g, ' ')
    .replace(/\b(the|a|an)\b/g, ' ')
    .replace(/&/g, ' and ')
    .replace(/[^a-z0-9+#]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function normalizeTitle(value) {
  return normalizeText(value)
    .replace(/\b(remote|hybrid|onsite|on site)\b/g, ' ')
    .replace(/\b(united states|usa|us)\b/g, ' ')
    .replace(/\b(fall|spring|summer|winter)\s+20\d{2}\b/g, match => match)
    .replace(/\s+/g, ' ')
    .trim();
}

function canonicalUrl(rawUrl) {
  const value = clean(rawUrl);
  if (!/^https?:\/\//i.test(value)) return '';

  try {
    const url = new URL(value);
    const host = url.hostname.toLowerCase().replace(/^www\./, '');
    const path = url.pathname.toLowerCase();
    const linkedIn = `${host}${path}`.match(/linkedin\.com\/(?:comm\/)?jobs\/view\/(\d+)/i);
    if (linkedIn) return `linkedin:${linkedIn[1]}`;

    const jobright = `${host}${path}`.match(/jobright\.ai\/jobs\/info\/([a-z0-9]+)/i);
    if (jobright) return `jobright:${jobright[1]}`;

    const glassdoorId = url.searchParams.get('jobListingId') || url.searchParams.get('jl');
    if (host.endsWith('glassdoor.com') && glassdoorId) return `glassdoor:${glassdoorId}`;

    const zipId = url.searchParams.get('jobid') || url.searchParams.get('jid') || url.searchParams.get('lvk');
    if (host.endsWith('ziprecruiter.com') && zipId) return `ziprecruiter:${zipId}`;

    url.hash = '';
    for (const key of [...url.searchParams.keys()]) {
      if (/^(utm_|src$|source$|campaign$|content$|cb$|guid$|uido$|cs$|jrtk$|tgt$|vt$|ao$|s$|pos$)/i.test(key)) {
        url.searchParams.delete(key);
      }
    }
    return `${host}${url.pathname}${url.search}`.toLowerCase();
  } catch {
    return value.toLowerCase();
  }
}

function semanticKey(json) {
  const company = normalizeText(json.company);
  const title = normalizeTitle(json.title);
  if (!company || !title) return '';
  return `${company}|${title}`;
}

function exactKey(json) {
  return clean(json.job_key).toLowerCase();
}

function shouldReprocessMemory(json) {
  return REPROCESS_STATUSES.has(clean(json.status).toLowerCase());
}

function looksLikeCandidate(json) {
  return (
    json.sheet_memory_record_type !== 'existing_sheet_row' &&
    Boolean(clean(json.job_key) || clean(json.title) || clean(json.url)) &&
    Boolean(clean(json.source_email_subject) || clean(json.message_id) || clean(json.from) || clean(json.email_date))
  );
}

function candidateRank(json) {
  const source = clean(json.source).toLowerCase();
  const sourceRank = SOURCE_RANK[source] || 0;
  const fit = Number(json.fit_score || 0);
  const hasUrl = /^https?:\/\//i.test(clean(json.url)) ? 5 : 0;
  const descriptionBonus = Math.min(5, Math.floor(clean(json.description).length / 300));
  return fit * 10 + sourceRank * 4 + hasUrl + descriptionBonus;
}

const existingExact = new Set();
const existingUrl = new Set();
const existingSemantic = new Set();
const candidates = [];

for (const item of items) {
  const json = item.json || {};

  if (json.sheet_memory_record_type === 'existing_sheet_row') {
    if (shouldReprocessMemory(json)) continue;

    const key = exactKey(json);
    const url = canonicalUrl(json.url);
    const semantic = semanticKey(json);
    if (key) existingExact.add(key);
    if (url) existingUrl.add(url);
    if (semantic) existingSemantic.add(semantic);
    continue;
  }

  if (looksLikeCandidate(json)) candidates.push(item);
}

const grouped = new Map();
const groupByUrl = new Map();
const groupBySemantic = new Map();
const skipped = {
  existing_exact: 0,
  existing_url: 0,
  existing_semantic: 0,
  in_run_duplicate: 0,
};

for (const item of candidates) {
  const json = item.json || {};
  const key = exactKey(json);
  const url = canonicalUrl(json.url);
  const semantic = semanticKey(json);

  if (key && existingExact.has(key)) {
    skipped.existing_exact += 1;
    continue;
  }
  if (url && existingUrl.has(url)) {
    skipped.existing_url += 1;
    continue;
  }
  if (semantic && existingSemantic.has(semantic)) {
    skipped.existing_semantic += 1;
    continue;
  }

  const urlGroup = url ? groupByUrl.get(url) : '';
  const semanticGroup = semantic ? groupBySemantic.get(semantic) : '';
  const groupKey = semanticGroup || urlGroup || semantic || url || key || JSON.stringify(json);
  const previous = grouped.get(groupKey);
  if (!previous || candidateRank(json) > candidateRank(previous.json || {})) {
    if (previous) skipped.in_run_duplicate += 1;
    grouped.set(groupKey, item);
  } else {
    skipped.in_run_duplicate += 1;
  }

  if (url) groupByUrl.set(url, groupKey);
  if (semantic) groupBySemantic.set(semantic, groupKey);
}

return [...grouped.entries()]
  .map(([groupKey, item], index) => ({
    json: {
      ...item.json,
      pre_ai_dedupe_group_key: groupKey,
      pre_ai_dedupe_index: index,
      pre_ai_existing_exact_skipped: skipped.existing_exact,
      pre_ai_existing_url_skipped: skipped.existing_url,
      pre_ai_existing_semantic_skipped: skipped.existing_semantic,
      pre_ai_in_run_duplicate_skipped: skipped.in_run_duplicate,
    },
  }))
  .sort((a, b) => Number(b.json.fit_score || 0) - Number(a.json.fit_score || 0));
